   116|	async function send(text: string, mode?: string) {
   117|		if ($streaming) return;
   118|		audioQueue?.prime();
   119|		const token=*** ? ($creds as Credentials | null)?.access_token ?? '' : guestToken ?? '';
   120|		// Only push user message if there's actual text (first turn may be empty — opens the session)
   121|		if (text.trim()) {
   122|			messages.update(m => [...m, { role: 'user', content: text }]);
   123|			if (guestMode) {
   124|				incrementGuestTurns();
   125|				guestTurns.set(getGuestTurns());
   126|			}
   127|		}
   128|		messages.update(m => [...m, { role: 'assistant', content: '' }]);
   129|		streaming.set(true);
   130|
   131|		try {
   132|			for await (const _ of chat(token, text, sessionId, (event) => {
   133|				if (event.type === 'session') {
   134|					sessionId = event.session_id as string;
   135|				} else if (event.type === 'token') {
   136|					messages.update(m => {
   137|						const last = m[m.length - 1];
   138|						last.content += event.text as string;
   139|						return [...m];
   140|					});
   141|				} else if (event.type === 'break') {
   142|					// Priestess finished one block — enqueue for TTS, then start fresh message
   143|					if ($ttsEnabled && audioQueue) {
   144|						const msgs = get(messages);
   145|						const last = msgs.at(-1);
   146|						if (last?.role === 'assistant' && last.content) {
   147|							audioQueue.enqueue(last.content);
   148|						}
   149|					}
   150|					messages.update(m => [...m, { role: 'assistant', content: '' }]);
   151|				} else if (event.type === 'draw' && event.card) {
   152|					// Clea triggered a contextual card draw server-side
   153|					const raw = event.card as any;
   154|					const deckMeta = availableDecks.find(d => d.id === raw.deck);
   155|					const cardData: CardData = {
   156|						id: raw.id,
   157|						deck: raw.deck,
   158|						deckLabel: raw.deckLabel ?? deckMeta?.meta?.name ?? raw.deck,
   159|						title: raw.title,
   160|						keywords: raw.keywords ?? [],
   161|						body: raw.body ?? '',
   162|					};
   163|					messages.update(m => [...m, { role: 'card', content: '', card: cardData, interpreted: false }]);
   164|				}
   165|			}, mode)) { /* yield */ }
   166|		} catch (e: unknown) {
   167|			const msg = e instanceof Error ? e.message : String(e);
   168|			if (msg.includes('guest_limit')) {
   169|				guestTurns.set(GUEST_LIMIT);
   170|			}
   171|		} finally {
   172|			// Remove any trailing empty assistant message
   173|			messages.update(m => m.filter((msg, i) => !(msg.role === 'assistant' && msg.content === '' && i === m.length - 1)));
   174|			// Enqueue last assistant message for TTS (catches streams with no 'break' event)
   175|			if ($ttsEnabled && audioQueue) {
   176|				const msgs = get(messages);
   177|				const last = msgs.at(-1);
   178|				if (last?.role === 'assistant' && last.content) {
   179|					audioQueue.enqueue(last.content);
   180|				}
   181|			}
   182|			streaming.set(false);
   183|		}
   184|	}
