   186|	// Open session on mount — /chat with no session_id bootstraps it
   187|	onMount(async () => {
   188|		window.addEventListener('keydown', handleGlobalKey);
   189|		window.addEventListener('keyup', handleGlobalKey);
   190|		if (guestMode) {
