   193|		} else if ($authed && $creds) {
   194|			const c = $creds as Credentials;
   195|			audioQueue = createAudioQueue((t) => tts(t, c.access_token, get(ttsVoice)));
   196|			totemSession = new TotemSession(c.access_token, c.seeker_id);
   197|			totemSession.load().catch(() => {}); // non-blocking, non-fatal
   198|		}
   199|		fetchDecks();
   200|		send('');
   201|	});
   202|
   203|	onDestroy(() => {
   204|		window.removeEventListener('keydown', handleGlobalKey);
   205|		window.removeEventListener('keyup', handleGlobalKey);
   206|		audioQueue?.flush();
   207|		audioQueue = null;
   208|		if (totemSession && sessionId) {
   209|			totemSession.distillAndSave(sessionId).catch(() => {});
   210|		}
   211|	});
