   213|	function handleKey(e: KeyboardEvent) {
   214|		if (e.key === 'Enter' && !e.shiftKey) {
   215|			e.preventDefault();
   216|			const text = input.trim();
   217|			input = '';
   218|			send(text);
   219|		}
   220|	}
