   222|	// ── PTT voice ─────────────────────────────────────────────────────────────
   223|	async function startListening() {
   224|		if (!navigator.mediaDevices?.getUserMedia) {
   225|			console.warn('getUserMedia not available — requires a secure context (HTTPS or localhost)');
   226|			return;
   227|		}
   228|		audioCtx ??= new AudioContext();
   229|		let stream: MediaStream;
   230|		try {
   231|			stream = await navigator.mediaDevices.getUserMedia({ audio: true });
   232|		} catch (e) {
   233|			console.error('getUserMedia failed:', e);
   234|			voiceState.set('idle');
   235|			return;
   236|		}
   237|
   238|		// waveform analyser
   239|		const src = audioCtx.createMediaStreamSource(stream);
   240|		const analyser = audioCtx.createAnalyser();
   241|		analyser.fftSize = 128;
   242|		src.connect(analyser);
   243|		const buf = new Float32Array(analyser.frequencyBinCount);
   244|		function tick() {
   245|			if ($voiceState !== 'listening') return;
   246|			analyser.getFloatTimeDomainData(buf);
   247|			waveform.set(buf.slice());
   248|			requestAnimationFrame(tick);
   249|		}
   250|
   251|		chunks = [];
   252|		mediaRecorder = new MediaRecorder(stream);
   253|		mediaRecorder.ondataavailable = e => { if (e.data.size > 0) chunks.push(e.data); };
   254|		mediaRecorder.start();
   255|		audioQueue?.prime();
   256|		voiceState.set('listening');
   257|		tick();
   258|	}
   259|
   260|	async function stopListening() {
   261|		if (!mediaRecorder) return;
   262|		voiceState.set('transcribing');
   263|		mediaRecorder.stop();
   264|		const token=*** ? (guestToken ?? '') : (($creds as Credentials | null)?.access_token ?? '');
   265|		await new Promise<void>(res => { mediaRecorder!.onstop = () => res(); });
   266|		const mimeType = mediaRecorder.mimeType || 'audio/webm';
   267|		const blob = new Blob(chunks, { type: mimeType });
   268|		if (blob.size === 0) { voiceState.set('idle'); return; }
   269|		mediaRecorder.stream.getTracks().forEach(t => t.stop());
   270|		mediaRecorder = null;
   271|
   272|		try {
   273|			const text = await stt(blob, token);
   274|			voiceState.set('idle');
   275|			if (text) {
   276|				if (!pttSeen) {
   277|					pttSeen = true;
   278|					localStorage.setItem(PTT_SEEN_KEY, '1');
   279|				}
   280|				send(text);
   281|			}
   282|		} catch (e) {
   283|			console.error('STT failed:', e);
   284|			voiceState.set('idle');
   285|		}
   286|	}
