   288|	// ── PTT keyboard shortcut (Space, held) ───────────────────────────────────
   289|	function handleGlobalKey(e: KeyboardEvent) {
   290|		// Only when textarea is not focused
   291|		if (document.activeElement?.tagName === 'TEXTAREA') return;
   292|		if (e.code === 'Space' && !e.repeat) {
   293|			e.preventDefault();
   294|			if (e.type === 'keydown') startListening();
   295|			else stopListening();
   296|		}
   297|	}
