     2|import { browser } from '$app/environment';
     3|
     4|// ── Auth ────────────────────────────────────────────────────────────────────
     5|export interface Credentials {
     6|	seeker_id: string;
     7|	access_token: string;
     8|	refresh_token: string;
     9|	handle?: string;
    10|	stage?: string;
    11|}
    12|
    13|function credStore() {
    14|	const stored = browser ? localStorage.getItem('clea_creds') : null;
    15|	const { subscribe, set } = writable<Credentials | null>(
    16|		stored ? JSON.parse(stored) : null
    17|	);
    18|	return {
    19|		subscribe,
    20|		login(c: Credentials) {
    21|			localStorage.setItem('clea_creds', JSON.stringify(c));
    22|			set(c);
    23|		},
    24|		logout() {
    25|			localStorage.removeItem('clea_creds');
    26|			set(null);
    27|		}
    28|	};
    29|}
    30|export const creds = credStore();
    31|export const authed=*** $c => $c !== null);
    32|
    33|// ── Chat ────────────────────────────────────────────────────────────────────
    34|export type Role = 'user' | 'assistant' | 'system' | 'card';
    35|
    36|export interface CardData {
    37|	id: string;
    38|	deck: string;
    39|	deckLabel: string;
    40|	title: string;
    41|	keywords: string[];
    42|	body: string;
    43|}
    44|
    45|export interface Message {
    46|	role: Role;
    47|	content: string;
    48|	card?: CardData;
    49|	interpreted?: boolean; // true once seeker has asked for interpretation
    50|}
    51|
    52|export const messages = writable<Message[]>([]);
    53|export const streaming = writable(false);
    54|
    55|// ── Voice ───────────────────────────────────────────────────────────────────
    56|export type VoiceState = 'idle' | 'listening' | 'transcribing' | 'speaking';
    57|export const voiceState = writable<VoiceState>('idle');
    58|export const ptt = writable(true);          // push-to-talk vs always-on
    59|export const waveform = writable<Float32Array>(new Float32Array(64));
    60|
    61|// ── Ambience ─────────────────────────────────────────────────────────────────
    62|export const ambience = writable(1.0);      // 0 = bare, 1 = full
    63|
    64|// ── Guest session ─────────────────────────────────────────────────────────────
    65|import { getGuestTurns } from './guestSession';
    66|
    67|// Reactive view of the guest turn counter. Updated by Chat.svelte after each turn.
    68|export const guestTurns = writable<number>(browser ? getGuestTurns() : 0);
    69|
    70|function ttsStore() {
    71|	const stored = browser ? localStorage.getItem('clea_tts') : null;
    72|	const { subscribe, set } = writable<boolean>(stored === 'true');
    73|	return {
    74|		subscribe,
    75|		set(v: boolean) {
    76|			if (browser) localStorage.setItem('clea_tts', String(v));
    77|			set(v);
    78|		}
    79|	};
    80|}
    81|export const ttsEnabled = ttsStore();
    82|
    83|export type TtsVoice = 'elf' | 'poet' | 'alien' | 'president';
    84|
    85|function ttsVoiceStore() {
    86|	const stored = browser ? (localStorage.getItem('clea_tts_voice') as TtsVoice | null) : null;
    87|	const { subscribe, set } = writable<TtsVoice>(stored ?? 'elf');
    88|	return {
    89|		subscribe,
    90|		set(v: TtsVoice) {
    91|			if (browser) localStorage.setItem('clea_tts_voice', v);
    92|			set(v);
    93|		}
    94|	};
    95|}
    96|export const ttsVoice = ttsVoiceStore();
