    10|
    11|  let wantsSignin = $state(false);
    12|  let exchanging = $state(false);
    13|  $effect(() => { if ($authed) wantsSignin = false; });
    14|
    15|  // Sync BetterAuth session cookie → our JWT after OAuth redirect
    16|  onMount(async () => {
    17|    if ($authed) return;
    18|    const BASE = import.meta.env.VITE_OURACLE_BASE_URL ?? 'https://api.ouracle.kerry.ink';
    19|    const { data } = await authClient.getSession();
    20|    if (!data?.session?.token) return;
    21|    exchanging = true;
    22|    try {
    23|      const r = await fetch(`${BASE}/auth/social-exchange`, {
    24|        method: 'POST',
    25|        headers: { 'Content-Type': 'application/json' },
    26|        body: JSON.stringify({ session_token: data.session.token }),
    27|      });
    28|      if (!r.ok) return;
    29|      const { seeker_id, access_token, refresh_token, handle, stage } = await r.json();
    30|      if (access_token && seeker_id) creds.login({ access_token, refresh_token: refresh_token ?? '', seeker_id, handle, stage });
    31|    } finally {
    32|      exchanging = false;
    33|    }
    34|  });
    35|</script>
