    43|  {#if !$authed && !exchanging && $guestTurns >= GUEST_LIMIT}
    44|    <AltarOverlay onsignin={() => (wantsSignin = true)} />
    45|  {/if}
    46|  {#if $authed && $creds?.stage !== 'covenanted'}
    47|    <Covenant onaccept={() => {}} />
    48|  {/if}
    49|{:else}
