     4|	return { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
     5|}
     6|
     7|// ── Auth ─────────────────────────────────────────────────────────────────────
     8|export async function signup(name: string, password: string) {
     9|	const r = await fetch(`${BASE}/seeker/new`, {
    10|		method: 'POST',
    11|		headers: { 'Content-Type': 'application/json' },
