    17|
    18|export async function signin(handle: string, password: string) {
    19|	const r = await fetch(`${BASE}/auth/token`, {
    20|		method: 'POST',
    21|		headers: { 'Content-Type': 'application/json' },
    22|		body: JSON.stringify({ handle, password })
    23|	});
    24|	if (!r.ok) throw new Error(await r.text());
    25|	return r.json();
    26|}
    27|
    28|// ── Chat (SSE) ────────────────────────────────────────────────────────────────
    29|// /chat handles both new sessions (no session_id) and continuing ones.
    30|// Events: { type: 'session', session_id, stage }
    31|//         { type: 'token', text }
    32|//         { type: 'break' }
    33|//         { type: 'complete', stage, session_id? }
    34|//         { type: 'error', message }
    35|export async function* chat(
    36|	token: string,
    37|	message: string,
    38|	sessionId: string | null,
    39|	onEvent: (event: Record<string, unknown>) => void,
    40|	mode?: string
    41|): AsyncGenerator<void> {
    42|	const r = await fetch(`${BASE}/chat`, {
    43|		method: 'POST',
    44|		headers: authHeaders(token),
    45|		body: JSON.stringify({ message, session_id: sessionId ?? undefined, ...(mode ? { mode } : {}) })
    46|	});
    47|	if (!r.ok) throw new Error(await r.text());
    48|	const reader = r.body!.getReader();
    49|	const dec = new TextDecoder();
    50|	while (true) {
    51|		const { done, value } = await reader.read();
    52|		if (done) break;
    53|		const text = dec.decode(value, { stream: true });
    54|		for (const line of text.split('\n')) {
    55|			if (!line.startsWith('data: ')) continue;
    56|			try {
    57|				const event = JSON.parse(line.slice(6));
    58|				onEvent(event);
    59|			} catch { /* skip malformed */ }
    60|		}
    61|		yield;
    62|	}
    63|}
    64|
    65|// ── TTS ───────────────────────────────────────────────────────────────────────
    66|export async function tts(text: string, token: string, voice?: string): Promise<ArrayBuffer> {
    67|	const r = await fetch(`${BASE}/tts`, {
    68|		method: 'POST',
    69|		headers: authHeaders(token),
    70|		body: JSON.stringify({ text, ...(voice ? { voice } : {}) })
    71|	});
    72|	if (!r.ok) throw new Error(await r.text());
    73|	return r.arrayBuffer();
